GameTitle = {}
GameTitle.TitleStatus = {
    NotHas = 1,
    Has = 2,
    Use = 3
}

GameTitle.TitleType = {
    KillWalkingDead = 1,
    KillPlayer = 2,
    GradeUp = 3,
    KillMonsterA = 4,
    SurvivalTime = 5
}

function GameTitle:initTitle(player)
    for _, configTitle in pairs(TitleConfig.Titles) do
        local isHas = false
        for _, title in pairs(player.titles) do
            if title.id == configTitle.Id then
                isHas = true
                break
            end
        end
        if not isHas then
            local data = {}
            data.id = configTitle.Id
            data.status = GameTitle.TitleStatus.NotHas
            table.insert(player.titles, data)
        end
        if not player.titleType[tostring(configTitle.Type)] then
            local data = {}
            data.type = configTitle.Type
            data.num = 0
            player.titleType[tostring(configTitle.Type)] = data
        end
    end
    self:sendTitleToClient(player)
end

function GameTitle:sendTitleToClient(player)
    local titles = {}
    for _, title in pairs(player.titles) do
        table.insert(titles, { Id = title.id, Status = title.status })
        if title.status == GameTitle.TitleStatus.Use then
            local config = TitleConfig:getTitleById(title.id)
            if config then
                local disName = "##" .. config.Name .. "##" .. "\n"
                disName = disName .. player.name
                player:setShowName(disName, 0)
            end
        end
    end
    local titleType = {}
    for _, typeTitle in pairs(player.titleType) do
        table.insert(titleType, { TypeId = typeTitle.type, Num = typeTitle.num })
    end
    GamePacketSender:sendWalkingDeadDesignationDetail(player.rakssid, titles, titleType)
end

function GameTitle:updateTitle(player, titleType, num)

    local configType = player.titleType[tostring(titleType)]
    if not configType then
        return
    end
    configType.num = configType.num + num
    local dataType = {}
    table.insert(dataType, { TypeId = configType.type, Num = configType.num })
    local data = {}
    for _, title in pairs(player.titles) do
        local config = TitleConfig:getTitleById(title.id)
        if config then
            if config.Type == titleType and configType.num >= config.Condition and title.status == GameTitle.TitleStatus.NotHas then
                title.status = GameTitle.TitleStatus.Has
                HostApi.broadCastMsgByType(player.rakssid, 1, 3, 166, config.Name)
                table.insert(data, { Id = title.id, Status = title.status })
            end
        end
    end
    GamePacketSender:sendWalkingDeadDesignationDetail(player.rakssid, data, dataType)
end

function GameTitle:unloadTitle(player, titleId)
    local oneTitle = {}
    for _, title in pairs(player.titles) do
        if title.id == titleId and title.status == GameTitle.TitleStatus.Use then
            title.status = GameTitle.TitleStatus.Has
            table.insert(oneTitle, { Id = titleId, Status = title.status })
            break
        end
    end
    GamePacketSender:sendWalkingDeadDesignationDetail(player.rakssid, oneTitle, "")
    local disName = player.name
    player:setShowName(disName, 0)
end

function GameTitle:useTitle(player, titleId)
    local twoTitle = {}
    for _, title in pairs(player.titles) do
        if title.status == GameTitle.TitleStatus.Use then
            title.status = GameTitle.TitleStatus.Has
            table.insert(twoTitle, { Id = title.id, Status = title.status })
            break
        end
    end
    local disName = ""
    for _, title in pairs(player.titles) do
        if title.id == titleId and title.status == GameTitle.TitleStatus.Has then
            title.status = GameTitle.TitleStatus.Use
            table.insert(twoTitle, { Id = title.id, Status = title.status })
            local config = TitleConfig:getTitleById(titleId)
            disName = "##" .. config.Name .. "##" .. "\n"
            break
        end
    end
    disName = disName .. player.name
    GamePacketSender:sendWalkingDeadDesignationDetail(player.rakssid, twoTitle, "")
    player:setShowName(disName, 0)
end

function GameTitle:updateMonsterTitle(player, monsterId)
    for _, titleType in pairs(TitleConfig.TitlesType) do
        for _, id in pairs(titleType.MonsterIds) do
            if tonumber(id) == monsterId then
                self:updateTitle(player, titleType.Type, 1)
            end
        end
    end
end

function GameTitle:updateSurvivalTimeTitle()
    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        if player.isLife then
            self:updateTitle(player, GameTitle.TitleType.SurvivalTime, 1)

        end
    end
end

return GameTitle

